import{_ as r,c as l,o as t,ae as a}from"./chunks/framework.Ck3L_38O.js";const m=JSON.parse('{"title":"6 - Isolation & System Call Entry_Exit","description":"","frontmatter":{},"headers":[],"relativePath":"course/6.S081/Lec6.md","filePath":"course/6.S081/Lec6.md"}'),s={name:"course/6.S081/Lec6.md"};function c(o,e,p,i,u,n){return t(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="_6-isolation-system-call-entry-exit" tabindex="-1">6 - Isolation &amp; System Call Entry_Exit <a class="header-anchor" href="#_6-isolation-system-call-entry-exit" aria-label="Permalink to &quot;6 - Isolation &amp; System Call Entry_Exit&quot;">​</a></h1><h2 id="trap" tabindex="-1">Trap <a class="header-anchor" href="#trap" aria-label="Permalink to &quot;Trap&quot;">​</a></h2><p>硬件：<br> 在 Risc-V 的 CPU 中会有 32 寄存器(registers)，其中一些是特殊的寄存器：</p><blockquote><p>栈指针 x2 sp (stack pointer)<br> 程序计数器 pc (program counter)</p></blockquote><blockquote><p>satp (satp) ，指向页表的指针，用于页表的查找<br> stvec (Supervisor Trap Vector Base Address) ，指向中断向量表的指针，用于处理 kernel 中的 trap<br> sepc (sepc) ，保存触发 trap 的指令地址，指向当前正在执行的指令的地址，用于保存系统调用的入口和出口，pc<br> sscratch (sscratch) ，用于保存 user 态和 kernel 态之间的切换状态</p></blockquote><hr><p>当 mode 是 user 模式的时候，拥有的权限是可以读写少数 control 寄存器，只能使用 PTE_U 的 PTE ，如果在 super 模式时，所有寄存器都可以读写，但是默认不使用 PTE_U 的 PTE。</p><p>在 trap 发生的之前， CPU 的所有状态都设置为运行 user 代码，而不是 kernel 代码。操作系统需要实现几点：<br><strong>需要透明的恢复 user 代码</strong>：特别是在 user 预期设备不会中断的情况下，希望让 kernel 实现中断，然后恢复 user 代码，而 user 感觉不到这个过程，因此不能让 kernel 干扰这个过程，也需要将原本的 kernel 的寄存器信息保存起来；<br><strong>需要实现安全和隔离</strong>： user 的代码不能干扰 user kernel 的转换，也不能依赖任何 user 态传递过来的东西，它们可能有恶意。 xv6 中，甚至不会去查看寄存器的值，只是保存起来。</p><hr><p>在系统当中，有 user 态和 kernel 态， user 态有 user 程序，，例如 shell ，当 shell 希望进行系统调用时，例如 write 。<br> 首先会将模式切换到 super 模式，因为需要使用到 kernel 的权限， satp 目前之前 user 页表，它只包含 user 程序需要的映射，但是 user 的页表没有 kernel 页表的映射，因此需要切换页表到 kernel 页表，栈指针需要指向 kernel 中某个位置的栈等等，切换完所有的寄存器状态。</p><p>当 shell 调用 write 时，write 会调用 ecall 指令，直接跳到 super mode</p><blockquote><p>之后的第一条指令是用 assembled 编写的 <code>uservec()</code> ，这是 trampoline 的一部分，它在 <em>trampoline.S</em> 中实现。<br> 接着执行 <em>trap.c</em> 中的 <code>usertrap()</code><br><code>usertrap()</code> 会调用 <code>syscall()</code> ，<code>syscall()</code> 会查看系统调用号 sys_write ，然后执行对应的系统调用<br> 当系统调用执行结束，返回时<br><code>sys_write()</code> 会返回到 <code>syscall()</code> 中<br><code>syscall()</code> 会返回到 <code>usertrap()</code><br> 然后 <code>usertrap()</code> 会调用<code>usertrapret()</code><br> 最后会返回到 <code>trampoline.S</code> 中的 <code>userret()</code> 中</p></blockquote><p>对于寄存器：</p><ol><li>ecall 前（用户态）</li></ol><ul><li>寄存器全是用户值：a7=系统调用号，a0..=参数，sp/ra… 也是用户的。</li></ul><ol start="2"><li>执行 ecall（硬件行为）</li></ol><ul><li>切到 S 态；sepc ← ecall 的地址；scause ← U-ecall；pc ← stvec；GPR 原封不动（仍是用户值）。</li></ul><ol start="3"><li>入口汇编 trampoline.S:uservec</li></ol><ul><li>从 sscratch 取到当前进程的 trapframe 指针。</li><li>把所有用户 GPR（ra、sp、a0..a7、…）保存到 trapframe。<br> 注：这一步“顺带”保存了系统调用参数和号，因为它们就在 a0..a7 里。</li><li>切到内核页表（写 satp + sfence.vma）、切到该进程的内核栈。</li><li>跳到 C 函数 trap.c:usertrap。</li></ul><ol start="4"><li>trap.c:usertrap（内核 C 入口）</li></ol><ul><li>p-&gt;trapframe-&gt;epc = r_sepc()（把硬件 CSR 里的 sepc 拷到 trapframe，用作返回的 pc）。</li><li>若是系统调用：p-&gt;trapframe-&gt;epc += 4（返回时跳过 ecall）；然后调用 syscall()。</li></ul><ol start="5"><li>syscall() 分发与执行</li></ol><ul><li>从 p-&gt;trapframe-&gt;a7 取系统调用号；从 p-&gt;trapframe-&gt;a0.. 取参数。</li><li>对指针参数用 copyin/copyout 校验并拷贝，避免直接信任用户地址。</li><li>调用具体 sys_* 实现；把返回值写回 p-&gt;trapframe-&gt;a0。</li></ul><ol start="6"><li>返回用户态准备 usertrapret → trampoline.S:userret</li></ol><ul><li>把 stvec 设回 uservec（为下一次 U→S 做好入口）。</li><li>userret：设置 sstatus.SPP=U；w_sepc(trapframe-&gt;epc)；切回用户页表；从 trapframe 逐一恢复所有 GPR（此时 a0 已是返回值）；sret 回到用户态，执行 ecall 之后的一条指令。</li></ul><hr><p>ecall 会将模式设置为 super ，然后将程序计数器保存到 sepc 中，然后将程序计数器设置为 stvec 的寄存器<br> ecall 所做的事情十分少，是因为 RISC-V 的设计者希望软件有更大的灵活性。</p>',27)])])}const _=r(s,[["render",c]]);export{m as __pageData,_ as default};
